1	use super::socket::{SocketId, SocketType};
2	use crate::common::ip_to_bytes;
3	use crate::seq_number::{AckSeqNumber, MsgNumber, SeqNumber};
4	use std::net::IpAddr;
5	use tokio::io::{Error, ErrorKind, Result};
6	
7	#[derive(Debug)]
8	pub(crate) struct UdtControlPacket {
9	    // bit 0 = 1
10	    pub packet_type: ControlPacketType, // bits 1-15 + Control Information Field (bits 128+)
11	    pub reserved: u16,                  // bits 16-31
12	    pub additional_info: u32,           // bits 32-63
13	    pub timestamp: u32,                 // bits 64-95
14	    pub dest_socket_id: SocketId,       // bits 96-127
15	}
16	
17	impl UdtControlPacket {
18	    pub fn new_handshake(hs: HandShakeInfo, dest_socket_id: SocketId) -> Self {
19	        Self {
20	            packet_type: ControlPacketType::Handshake(hs),
21	            reserved: 0,
22	            additional_info: 0,
23	            timestamp: 0,
24	            dest_socket_id,
25	        }
26	    }
27	
28	    pub fn new_nak(loss_list: Vec<u32>, dest_socket_id: SocketId) -> Self {
29	        Self {
30	            packet_type: ControlPacketType::Nak(NakInfo {
31	                loss_info: loss_list,
32	            }),
33	            reserved: 0,
34	            additional_info: 0,
35	            timestamp: 0,
36	            dest_socket_id,
37	        }
38	    }
39	
40	    pub fn new_ack2(seq: AckSeqNumber, dest_socket_id: SocketId) -> Self {
41	        Self {
42	            packet_type: ControlPacketType::Ack2,
43	            additional_info: seq.number(),
44	            dest_socket_id,
45	            reserved: 0,
46	            timestamp: 0,
47	        }
48	    }
49	
50	    pub fn new_drop(
51	        msg_id: MsgNumber,
52	        first: SeqNumber,
53	        last: SeqNumber,
54	        dest_socket_id: SocketId,
55	    ) -> Self {
56	        Self {
57	            packet_type: ControlPacketType::MsgDropRequest(DropRequestInfo {
58	                first_seq_number: first,
59	                last_seq_number: last,
60	            }),
61	            additional_info: msg_id.number(),
62	            dest_socket_id,
63	            reserved: 0,
64	            timestamp: 0,
65	        }
66	    }
67	
68	    pub fn new_keep_alive(dest_socket_id: SocketId) -> Self {
69	        Self {
70	            packet_type: ControlPacketType::KeepAlive,
71	            dest_socket_id,
72	            additional_info: 0,
73	            reserved: 0,
74	            timestamp: 0,
75	        }
76	    }
77	
78	    pub fn new_shutdown(dest_socket_id: SocketId) -> Self {
79	        Self {
80	            packet_type: ControlPacketType::Shutdown,
81	            dest_socket_id,
82	            additional_info: 0,
83	            reserved: 0,
84	            timestamp: 0,
85	        }
86	    }
87	
88	    pub fn new_ack(
89	        ack_number: AckSeqNumber,
90	        next_seq_number: SeqNumber,
91	        dest_socket_id: SocketId,
92	        info: Option<AckOptionalInfo>,
93	    ) -> Self {
94	        Self {
95	            packet_type: ControlPacketType::Ack(AckInfo {
96	                next_seq_number,
97	                info,
98	            }),
99	            dest_socket_id,
100	            additional_info: ack_number.number(),
101	            reserved: 0,
102	            timestamp: 0,
103	        }
104	    }
105	
106	    pub fn ack_seq_number(&self) -> Option<AckSeqNumber> {
107	        match self.packet_type {
108	            ControlPacketType::Ack(_) => Some(self.additional_info.into()),
109	            ControlPacketType::Ack2 => Some(self.additional_info.into()),
110	            _ => None,
111	        }
112	    }
113	
114	    pub fn msg_seq_number(&self) -> Option<MsgNumber> {
115	        match self.packet_type {
116	            ControlPacketType::MsgDropRequest(_) => {
117	                Some((self.additional_info & MsgNumber::MAX_NUMBER).into())
118	            }
119	            _ => None,
120	        }
121	    }
122	
123	    pub fn serialize(&self) -> Vec<u8> {
124	        let mut buffer: Vec<u8> = Vec::with_capacity(8);
125	        buffer.extend_from_slice(&(0x8000 + self.packet_type.type_as_u15()).to_be_bytes());
126	        buffer.extend_from_slice(&self.reserved.to_be_bytes());
127	        buffer.extend_from_slice(&self.additional_info.to_be_bytes());
128	        buffer.extend_from_slice(&self.timestamp.to_be_bytes());
129	        buffer.extend_from_slice(&self.dest_socket_id.to_be_bytes());
130	        buffer.extend_from_slice(&self.packet_type.control_info_field());
131	        buffer
132	    }
133	
134	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
135	        if raw.len() < 16 {
136	            return Err(Error::new(
137	                ErrorKind::InvalidData,
138	                "control packet header is too short",
139	            ));
140	        }
141	        let reserved = u16::from_be_bytes(raw[2..4].try_into().unwrap());
142	        let additional_info = u32::from_be_bytes(raw[4..8].try_into().unwrap());
143	        let timestamp = u32::from_be_bytes(raw[8..12].try_into().unwrap());
144	        let dest_socket_id = u32::from_be_bytes(raw[12..16].try_into().unwrap());
145	
146	        let packet_type = ControlPacketType::deserialize(raw)?;
147	        Ok(Self {
148	            reserved,
149	            additional_info,
150	            timestamp,
151	            dest_socket_id,
152	            packet_type,
153	        })
154	    }
155	}
156	
157	#[derive(Debug)]
158	pub(crate) enum ControlPacketType {
159	    Handshake(HandShakeInfo),
160	    KeepAlive,
161	    Ack(AckInfo),
162	    Nak(NakInfo),
163	    Shutdown,
164	    Ack2,
165	    MsgDropRequest(DropRequestInfo),
166	    UserDefined,
167	}
168	
169	impl ControlPacketType {
170	    pub fn type_as_u15(&self) -> u16 {
171	        match self {
172	            Self::Handshake(_) => 0x0000,
173	            Self::KeepAlive => 0x0001,
174	            Self::Ack(_) => 0x0002,
175	            Self::Nak(_) => 0x0003,
176	            Self::Shutdown => 0x0005,
177	            Self::Ack2 => 0x0006,
178	            Self::MsgDropRequest(_) => 0x0007,
179	            Self::UserDefined => 0x7fff,
180	        }
181	    }
182	
183	    pub fn control_info_field(&self) -> Vec<u8> {
184	        match self {
185	            Self::Handshake(hs) => hs.serialize(),
186	            Self::Ack(ack) => ack.serialize(),
187	            Self::Nak(nak) => nak.serialize(),
188	            Self::MsgDropRequest(drop) => drop.serialize(),
189	            _ => vec![],
190	        }
191	    }
192	
193	    pub fn deserialize(raw_control_packet: &[u8]) -> Result<Self> {
194	        let type_id = u16::from_be_bytes(raw_control_packet[0..2].try_into().unwrap()) & 0x7FFF;
195	        let packet = match type_id {
196	            0x0000 => Self::Handshake(HandShakeInfo::deserialize(&raw_control_packet[16..])?),
197	            0x0001 => Self::KeepAlive,
198	            0x0002 => Self::Ack(AckInfo::deserialize(&raw_control_packet[16..])?),
199	            0x0003 => Self::Nak(NakInfo::deserialize(&raw_control_packet[16..])?),
200	            0x0005 => Self::Shutdown,
201	            0x0006 => Self::Ack2,
202	            0x0007 => {
203	                Self::MsgDropRequest(DropRequestInfo::deserialize(&raw_control_packet[16..])?)
204	            }
205	            0x7fff => Self::UserDefined,
206	            _ => {
207	                return Err(Error::new(
208	                    ErrorKind::InvalidData,
209	                    "unknown control packet type",
210	                ));
211	            }
212	        };
213	        Ok(packet)
214	    }
215	}
216	
217	#[derive(Debug, Clone)]
218	pub(crate) struct HandShakeInfo {
219	    pub udt_version: u32,
220	    pub socket_type: SocketType,
221	    pub initial_seq_number: SeqNumber,
222	    pub max_packet_size: u32,
223	    pub max_window_size: u32,
224	    pub connection_type: i32, // regular or rendezvous
225	    pub socket_id: SocketId,
226	    pub syn_cookie: u32,
227	    pub ip_address: IpAddr,
228	}
229	
230	impl HandShakeInfo {
231	    pub fn serialize(&self) -> Vec<u8> {
232	        [
233	            self.udt_version,
234	            self.socket_type as u32,
235	            self.initial_seq_number.number(),
236	            self.max_packet_size,
237	            self.max_window_size,
238	        ]
239	        .iter()
240	        .flat_map(|v| v.to_be_bytes())
241	        .chain(self.connection_type.to_be_bytes().into_iter())
242	        .chain(self.socket_id.to_be_bytes().into_iter())
243	        .chain(self.syn_cookie.to_be_bytes().into_iter())
244	        .chain(ip_to_bytes(self.ip_address))
245	        .collect()
246	    }
247	
248	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
249	        let get_u32 =
250	            |idx: usize| u32::from_be_bytes(raw[(idx * 4)..(idx + 1) * 4].try_into().unwrap());
251	        let addr: IpAddr = {
252	            if raw[36..48].iter().all(|b| *b == 0) {
253	                // IPv4
254	                let octets: [u8; 4] = raw[32..36].try_into().unwrap();
255	                octets.into()
256	            } else {
257	                // IPv6
258	                let octets: [u8; 16] = raw[32..48].try_into().unwrap();
259	                octets.into()
260	            }
261	        };
262	
263	        Ok(Self {
264	            udt_version: get_u32(0),
265	            socket_type: get_u32(1).try_into()?,
266	            initial_seq_number: get_u32(2).into(),
267	            max_packet_size: get_u32(3),
268	            max_window_size: get_u32(4),
269	            connection_type: i32::from_be_bytes(raw[20..24].try_into().unwrap()),
270	            socket_id: get_u32(6),
271	            syn_cookie: get_u32(7),
272	            ip_address: addr,
273	        })
274	    }
275	}
276	
277	#[derive(Debug)]
278	pub(crate) struct AckInfo {
279	    /// The packet sequence number to which all the
280	    /// previous packets have been received (excluding)
281	    pub next_seq_number: SeqNumber,
282	    pub info: Option<AckOptionalInfo>,
283	}
284	
285	impl AckInfo {
286	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
287	        let get_u32 =
288	            |idx: usize| u32::from_be_bytes(raw[(idx * 4)..(idx + 1) * 4].try_into().unwrap());
289	
290	        let next_seq_number: SeqNumber = get_u32(0).into();
291	
292	        if raw.len() <= 4 {
293	            return Ok(Self {
294	                next_seq_number,
295	                info: None,
296	            });
297	        }
298	        let info = AckOptionalInfo {
299	            rtt: get_u32(1),
300	            rtt_variance: get_u32(2),
301	            available_buf_size: get_u32(3),
302	            pack_recv_rate: get_u32(4),
303	            link_capacity: get_u32(5),
304	        };
305	        Ok(Self {
306	            next_seq_number,
307	            info: Some(info),
308	        })
309	    }
310	
311	    pub fn serialize(&self) -> Vec<u8> {
312	        match &self.info {
313	            None => self.next_seq_number.number().to_be_bytes().to_vec(),
314	            Some(extra) => [
315	                self.next_seq_number.number(),
316	                extra.rtt,
317	                extra.rtt_variance,
318	                extra.available_buf_size,
319	                extra.pack_recv_rate,
320	                extra.link_capacity,
321	            ]
322	            .iter()
323	            .flat_map(|v| v.to_be_bytes())
324	            .collect(),
325	        }
326	    }
327	}
328	
329	#[derive(Debug)]
330	pub(crate) struct AckOptionalInfo {
331	    /// RTT in microseconds
332	    pub rtt: u32,
333	    pub rtt_variance: u32,
334	    pub available_buf_size: u32,
335	    pub pack_recv_rate: u32,
336	    pub link_capacity: u32,
337	}
338	
339	#[derive(Debug)]
340	pub(crate) struct NakInfo {
341	    pub loss_info: Vec<u32>,
342	}
343	
344	impl NakInfo {
345	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
346	        let losses: Vec<u32> = raw
347	            .chunks(4)
348	            .filter_map(|chunk| {
349	                if chunk.len() < 4 {
350	                    return None;
351	                }
352	                Some(u32::from_be_bytes(chunk.try_into().unwrap()))
353	            })
354	            .collect();
355	        Ok(Self { loss_info: losses })
356	    }
357	
358	    pub fn serialize(&self) -> Vec<u8> {
359	        self.loss_info
360	            .iter()
361	            .flat_map(|x| x.to_be_bytes())
362	            .collect()
363	    }
364	}
365	
366	#[derive(Debug)]
367	pub(crate) struct DropRequestInfo {
368	    pub first_seq_number: SeqNumber,
369	    pub last_seq_number: SeqNumber,
370	}
371	
372	impl DropRequestInfo {
373	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
374	        let get_u32 =
375	            |idx: usize| u32::from_be_bytes(raw[(idx * 4)..(idx + 1) * 4].try_into().unwrap());
376	
377	        Ok(Self {
378	            first_seq_number: get_u32(0).into(),
379	            last_seq_number: get_u32(1).into(),
380	        })
381	    }
382	
383	    pub fn serialize(&self) -> Vec<u8> {
384	        [
385	            self.first_seq_number.number(),
386	            self.last_seq_number.number(),
387	        ]
388	        .iter()
389	        .flat_map(|x| x.to_be_bytes())
390	        .collect()
391	    }
392	}
